  let base_iva_0_no_sujeto = 0, cuota_iva_0_no_sujeto = 0;

  if (datos.desglose_iva && Array.isArray(datos.desglose_iva)) {
    for (const linea of datos.desglose_iva) {
      const tipo = Number(linea.tipo_iva);
      const base = Number(linea.base) || 0;
      const cuota = Number(linea.cuota) || 0;
      const exencion = (linea.tipo_exencion || "exento").toLowerCase();

      if (tipo === 21) { base_iva_21 += base; cuota_iva_21 += cuota; }
      else if (tipo === 12) { base_iva_12 += base; cuota_iva_12 += cuota; }
      else if (tipo === 10.5) { base_iva_10_5 += base; cuota_iva_10_5 += cuota; }
      else if (tipo === 10) { base_iva_10 += base; cuota_iva_10 += cuota; }
      else if (tipo === 5) { base_iva_5 += base; cuota_iva_5 += cuota; }
      else if (tipo === 4) { base_iva_4 += base; cuota_iva_4 += cuota; }
      else if (tipo === 0) {
        if (exencion === "no_sujeto") { base_iva_0_no_sujeto += base; cuota_iva_0_no_sujeto += cuota; }
        else if (exencion === "no_exento") { base_iva_0_no_ex += base; cuota_iva_0_no_ex += cuota; }
        else { base_iva_0 += base; cuota_iva_0 += cuota; }
      }
    }
  }

  let tipo_iva_principal = 21, max_base = 0;
  if (datos.desglose_iva && Array.isArray(datos.desglose_iva)) {
    for (const linea of datos.desglose_iva) {
      if (Number(linea.base) > max_base) { max_base = Number(linea.base); tipo_iva_principal = Number(linea.tipo_iva); }
    }
  }

  const cuotaIvaTotal = datos.total_iva ||
    (datos.desglose_iva ? datos.desglose_iva.reduce((sum, d) => sum + (Number(d.cuota) || 0), 0) : 0);

  return [{
    json: {
      ...datos,
      tipo_documento: datos.tipo_documento || "compra",
      tipo_iva_principal,
      cuota_iva_total: cuotaIvaTotal,
      base_iva_21, cuota_iva_21,
      base_iva_12, cuota_iva_12,
      base_iva_10_5, cuota_iva_10_5,
      base_iva_10, cuota_iva_10,
      base_iva_5, cuota_iva_5,
      base_iva_4, cuota_iva_4,
      base_iva_0, cuota_iva_0,
      base_iva_0_no_ex, cuota_iva_0_no_ex,
      base_iva_0_no_sujeto, cuota_iva_0_no_sujeto,
      metodo_pago: datos.forma_pago || datos.metodo_pago || "",
      pct_retencion: datos.retencion_irpf ? datos.retencion_irpf.porcentaje : 0,
      retencion: datos.retencion_irpf ? datos.retencion_irpf.cuota : 0,
