      cuota_req: datos.recargo_equivalencia ? datos.recargo_equivalencia.cuota : 0
    }
  }];
} catch (e) {
  return [{ json: { parse_ok: false, error: e.message, raw_response: textContent, confianza: 0 } }];
}

