// Datos extraidos por la IA - con guard isExecuted
let ia;
try {
  if ($('5-PDF. Parsear Claude1').isExecuted) {
    ia = $('5-PDF. Parsear Claude1').first().json;
  } else {
    ia = $('5. Parsear Respuesta IA').first().json;
  }
} catch(e) {
  try { ia = $('5. Parsear Respuesta IA').first().json; } catch(e2) {
    try { ia = $('5-PDF. Parsear Claude1').first().json; } catch(e3) {
      ia = { parse_ok: false, confianza: 0 };
    }
  }
}

// Obtener CIF de la empresa desde config
let cifEmpresa = '';
try {
  const configItems = $('7d. Buscar Config Empresa').all();
  if (configItems.length > 0 && configItems[0].json.cif_empresa) {
    cifEmpresa = configItems[0].json.cif_empresa.trim().toUpperCase().replace(/[^A-Z0-9]/g, '');
  }
} catch(e) {
  cifEmpresa = '';
}

const nifEmisorRaw = (ia.nif_emisor || '').trim().toUpperCase().replace(/[^A-Z0-9]/g, '');
const nifReceptorRaw = (ia.nif_receptor || '').trim().toUpperCase().replace(/[^A-Z0-9]/g, '');

// Determinar tipo_documento comparando CIF empresa con emisor/receptor
let tipoDoc;
const esRectificativa = (ia.tipo_documento || '').toLowerCase() === 'rectificativa';
if (cifEmpresa && !esRectificativa) {
  if (cifEmpresa === nifEmisorRaw) {
    tipoDoc = 'venta';
  } else if (cifEmpresa === nifReceptorRaw) {
    tipoDoc = 'compra';
  } else {
    tipoDoc = (ia.tipo_documento || 'compra').toLowerCase();
  }
} else {
  tipoDoc = (ia.tipo_documento || 'compra').toLowerCase();
}
const esVenta = tipoDoc === 'venta';

// PROVEEDORES (para facturas de compra)
const provItems = $('7a. Buscar Proveedor').all().filter(i => i.json.Id);

// CLIENTES (para facturas de venta)
let clienteItems = [];
try {
  clienteItems = $('7c. Buscar Clientes').all().filter(i => i.json.Id);
} catch(e) {
  clienteItems = [];
}

const nombreIA = (ia.nombre_emisor || '').trim().toLowerCase();
const nifIA = (ia.nif_emisor || '').trim().toUpperCase();
const nifValido = nifIA && nifIA !== 'SINNIF' && nifIA !== 'N/A' && nifIA !== 'NULL' && nifIA !== '';

// Para venta: el receptor es el cliente
const nombreReceptor = (ia.nombre_receptor || '').trim().toLowerCase();
const nifReceptor = (ia.nif_receptor || '').trim().toUpperCase();
const nifReceptorValido = nifReceptor && nifReceptor !== 'SINNIF' && nifReceptor !== 'N/A' && nifReceptor !== 'NULL' && nifReceptor !== '';

let proveedor = null;
let cliente = null;
let proveedorExiste = false;
let clienteExiste = false;
let terceroNuevo = false;

if (esVenta) {
  // Buscar cliente por NIF del receptor
  if (nifReceptorValido) {
    cliente = clienteItems.find(i => (i.json.nif || '').toUpperCase() === nifReceptor)?.json || null;
  }
  if (!cliente && nombreReceptor) {
    cliente = clienteItems.find(i => (i.json.nombre || '').trim().toLowerCase() === nombreReceptor)?.json || null;
  }
  clienteExiste = !!cliente;
  terceroNuevo = !clienteExiste;
} else {
  // Buscar proveedor por NIF del emisor
  if (nifValido) {
    proveedor = provItems.find(i => (i.json.nif_proveedor || '').toUpperCase() === nifIA)?.json || null;
  }
  if (!proveedor && nombreIA) {
    proveedor = provItems.find(i => (i.json.nombre_proveedor || '').trim().toLowerCase() === nombreIA)?.json || null;
  }
  proveedorExiste = !!proveedor;
  terceroNuevo = !proveedorExiste;
}

// REGLAS de asignacion de cuenta
const reglaItems = $('7b. Buscar Reglas').all();
const reglas = reglaItems.map(i => i.json).filter(r => r.Id);

let cuenta_gasto = ia.cuenta_gasto_sugerida || (esVenta ? '700' : '629');
let origen_cuenta = 'ia';

// Para ventas, forzar cuenta de ingreso si la IA sugiere gasto
if (esVenta && !cuenta_gasto.startsWith('7')) {
  cuenta_gasto = '700';
}

const nifBuscar = esVenta ? nifReceptor : nifIA;
const nifBuscarValido = esVenta ? nifReceptorValido : nifValido;

if (nifBuscarValido) {
  const reglaNif = reglas.find(r => r.tipo_regla === 'por_nif' && r.condicion && r.condicion.toUpperCase() === nifBuscar);
  if (reglaNif) { cuenta_gasto = reglaNif.cuenta_gasto; origen_cuenta = 'regla_nif'; }
}
if (origen_cuenta === 'ia') {
  const textoFactura = ((ia.nombre_emisor || '') + ' ' + (ia.nombre_receptor || '') + ' ' + (ia.conceptos ? ia.conceptos.map(c => c.descripcion).join(' ') : '')).toLowerCase();
  const reglaConcepto = reglas.find(r => (r.tipo_regla === 'por_concepto' || r.tipo_regla === 'por_nombre') && r.condicion && textoFactura.includes(r.condicion.toLowerCase()));
  if (reglaConcepto) { cuenta_gasto = reglaConcepto.cuenta_gasto; origen_cuenta = 'regla_concepto'; }
  else if (!esVenta && proveedorExiste && proveedor.cuenta_gasto) { cuenta_gasto = proveedor.cuenta_gasto; origen_cuenta = 'proveedor'; }
  else if (esVenta && clienteExiste && cliente.cuenta_ingresos) { cuenta_gasto = cliente.cuenta_ingresos; origen_cuenta = 'cliente'; }
}

return [{
  json: {
    numero_factura: ia.numero_factura, fecha_factura: ia.fecha_factura,
    nif_emisor: ia.nif_emisor, nombre_emisor: ia.nombre_emisor,
    nif_receptor: ia.nif_receptor || '', nombre_receptor: ia.nombre_receptor || '',
    base_imponible: ia.base_imponible, tipo_iva: ia.tipo_iva_principal,
    cuota_iva: ia.cuota_iva_total,
    tipo_retencion: ia.pct_retencion || ia.retencion_porcentaje || 0,
    cuota_retencion: ia.retencion || ia.retencion_cuota || 0,
    total_factura: ia.total_factura,
    cuenta_gasto, origen_cuenta,
    proveedor_existe: proveedorExiste,
    proveedor_id: proveedorExiste ? proveedor.Id : null,
    cliente_existe: clienteExiste,
    cliente_id: clienteExiste ? cliente.Id : null,
    tercero_nuevo: terceroNuevo,
    confianza: ia.confianza || 3, raw_response: ia.raw_response,
    tipo_documento: tipoDoc,
    metodo_pago: ia.metodo_pago || '',
    pct_retencion: ia.pct_retencion || 0,
    retencion: ia.retencion || 0,
    base_iva_21: ia.base_iva_21 || 0, cuota_iva_21: ia.cuota_iva_21 || 0,
    base_iva_12: ia.base_iva_12 || 0, cuota_iva_12: ia.cuota_iva_12 || 0,
    base_iva_10_5: ia.base_iva_10_5 || 0, cuota_iva_10_5: ia.cuota_iva_10_5 || 0,
    base_iva_10: ia.base_iva_10 || 0, cuota_iva_10: ia.cuota_iva_10 || 0,
    base_iva_5: ia.base_iva_5 || 0, cuota_iva_5: ia.cuota_iva_5 || 0,
    base_iva_4: ia.base_iva_4 || 0, cuota_iva_4: ia.cuota_iva_4 || 0,
    base_iva_0: ia.base_iva_0 || 0, cuota_iva_0: ia.cuota_iva_0 || 0,
    base_iva_0_no_ex: ia.base_iva_0_no_ex || 0, cuota_iva_0_no_ex: ia.cuota_iva_0_no_ex || 0,
    base_iva_0_no_sujeto: ia.base_iva_0_no_sujeto || 0, cuota_iva_0_no_sujeto: ia.cuota_iva_0_no_sujeto || 0,
